import pandas as pd
import numpy as np

# Load a sample of the data to see its structure
df = pd.read_csv('train.csv', nrows=5)
print(df.head())
print(df.info())

# Let's see the full shape and label distribution
df_full = pd.read_csv('train.csv')
print("Shape:", df_full.shape)
print("Label distribution:\n", df_full['label'].value_counts())

# Check a single heartbeat signal length
sample_signal = df_full['heartbeat_signals'].iloc[0]
signal_values = [float(x) for x in sample_signal.split(',')]
print("Signal length:", len(signal_values))




